600	/// Full path of the `.claude` session repo for a given workspace
601	/// root. Centralized so a future layout change (e.g. configurable
602	/// session-repo name) has one caller to update.
603	fn claude_path(workspace_root: &Path) -> PathBuf {
604	    workspace_root.join(".claude")
605	}
606	
607	/// Print the resumed stage (or "no saved state") and return.
608	fn cmd_status(layout: &StateLayout) -> Result<(), Box<dyn std::error::Error>> {
609	    match PushState::load(&layout.path)? {
610	        Some(state) => {
611	            info!(
612	                "push-state: stage={} bookmark={} started={} (file: {})",
613	                state.stage.as_str(),
614	                state.bookmark,
615	                state.started_at,
616	                layout.path.display()
617	            );
618	        }
619	        None => {
620	            info!(
621	                "push-state: no saved state ({} does not exist)",
622	                layout.path.display()
623	            );
624	        }
625	    }
626	    Ok(())
627	}
628	
629	/// Walk the state machine from `state.stage` to the end, saving
630	/// progress after each stage.
631	///
632	/// Records a `jj op` snapshot in both repos the first time we enter
633	/// `commit-app` and leaves it in state so resume inherits the
634	/// rollback target. On failure inside the rollback-eligible window
635	/// (`commit-app` / `commit-claude` / `bookmark-both`), both repos
636	/// are restored before the error propagates.
637	fn run_from(
638	    root: &Path,
639	    state: &mut PushState,
640	    args: &PushArgs,
641	    layout: &StateLayout,
642	) -> Result<(), Box<dyn std::error::Error>> {
643	    // State-sanity preflight: catch stale-state-after-out-of-band-recovery
644	    // (no-op on fresh state). Runs before save so a bogus halt point isn't
645	    // re-persisted. Per chores-06 [61] design.
646	    verify_state_sanity(root, state)?;
647	
648	    // Only persist state in real runs. Dry-runs are inspection-only
649	    // — carrying their inferred chids / op snapshots into real runs
650	    // would mislead the user about what was actually recorded.
651	    if !args.dry_run {
652	        state.save(&layout.path)?;
653	    }
654	    loop {
655	        let stage = state.stage;
656	
657	        // Snapshot op ids once on first `commit-app` entry. Skipped
658	        // in dry-run since we won't mutate anything to roll back.
659	        if stage == Stage::CommitApp && state.op_app.is_none() && !args.dry_run {
660	            state.op_app = Some(current_op_id(root)?);
661	            state.op_claude = Some(current_op_id(&claude_path(root))?);
662	            state.save(&layout.path)?;
663	        }
664	
665	        let result = run_stage(root, stage, state, args, layout);
666	
667	        if let Err(e) = &result {
668	            if stage_is_rollback_eligible(stage) && !args.dry_run {
669	                rollback_on_failure(root, state, e.as_ref());
670	            }
671	            return result;
672	        }
673	
674	        let next = stage.next();
675	
676	        // --step: pause between every stage so the user can inspect
677	        // intermediate state before the next one runs. Only if
678	        // there's a next stage to gate, and skipped entirely when
679	        // --yes is set or stdin isn't a tty (the prompt would hang
680	        // in scripted contexts — the script is presumed consenting).
681	        if args.step && next.is_some() {
682	            if args.yes {
683	                debug!(
684	                    "push step: --yes skips step gate between {} and next",
685	                    stage.as_str()
686	                );
687	            } else if !is_stdin_tty() {
688	                return Err("push: --step requires a tty (stdin is not interactive); \
689	                            add --yes to bypass step gates in non-interactive contexts"
690	                    .into());
691	            } else {
692	                let answer = prompt(&format!(
693	                    "push step: {} done. Continue to {}? [y/N] ",
694	                    stage.as_str(),
695	                    next.map(Stage::as_str).unwrap_or("")
696	                ))?;
697	                let normalized = answer.trim().to_ascii_lowercase();
698	                if normalized != "y" && normalized != "yes" {
699	                    return Err(format!(
700	                        "push: step gate declined after {} (got {answer:?})",
701	                        stage.as_str()
702	                    )
703	                    .into());
704	                }
705	            }
706	        }
707	
708	        match next {
709	            Some(n) => {
710	                state.stage = n;
711	                if !args.dry_run {
712	                    state.save(&layout.path)?;
713	                }
714	            }
715	            None => break,
716	        }
717	    }
718	    if args.dry_run {
719	        info!("push: DRY-RUN complete — no changes written");
720	    } else {
721	        // Honest completion: verify the world matches state before
722	        // declaring success. Catches the 0.37.1 false-success symptom
723	        // (stages "ran" but didn't actually commit / push what state
724	        // says they did). Warning-only because work has already
725	        // crossed the remote boundary by this point — rollback isn't
726	        // sound, the user needs to investigate.
727	        match verify_completion_sanity(root, state) {
728	            Ok(()) => {
729	                if layout.path.exists() {
730	                    fs::remove_file(&layout.path)?;
731	                }
732	                info!("push: completed all stages (verified, state cleared)");
733	            }
734	            Err(e) => {
735	                if layout.path.exists() {
736	                    fs::remove_file(&layout.path)?;
737	                }
738	                warn!("push: completed stages but post-completion verification failed:");
739	                warn!("  {e}");
740	                warn!(
741	                    "  state cleared anyway (work landed on remote); investigate the \
742	                     discrepancy before next push"
743	                );
744	            }
745	        }
746	    }
747	    Ok(())
748	}
