750	/// Whether a failure in `stage` should trigger the cross-repo op
751	/// restore. Anything at or past `push-app` crosses the remote
752	/// boundary — the app commit is live on origin, rollback is no
753	/// longer sound — so those failures propagate without touching
754	/// snapshots.
755	fn stage_is_rollback_eligible(stage: Stage) -> bool {
756	    matches!(
757	        stage,
758	        Stage::CommitApp | Stage::CommitClaude | Stage::BookmarkBoth
759	    )
760	}
761	
762	/// Restore both repos to their `jj op` snapshots, if we have them.
763	///
764	/// Best-effort — if the restore itself fails we warn but don't
765	/// shadow the original error the caller will propagate. Exposed at
766	/// `pub(crate)` so integration tests can exercise the rollback path
767	/// directly rather than forcing a stage failure.
768	pub(crate) fn rollback_on_failure(
769	    root: &Path,
770	    state: &PushState,
771	    original: &dyn std::error::Error,
772	) {
773	    warn!("push: rolling back both repos after: {original}");
774	    if let Some(op) = &state.op_app {
775	        match op_restore(root, op) {
776	            Ok(()) => info!("push: restored app repo to op {op}"),
777	            Err(e) => warn!("push: app repo restore failed: {e}"),
778	        }
779	    }
780	    if let Some(op) = &state.op_claude {
781	        match op_restore(&claude_path(root), op) {
782	            Ok(()) => info!("push: restored .claude to op {op}"),
783	            Err(e) => warn!("push: .claude restore failed: {e}"),
784	        }
785	    }
786	}
