788	/// Execute one stage. Arms mirror `Stage`'s declaration order.
789	fn run_stage(
790	    root: &Path,
791	    stage: Stage,
792	    state: &mut PushState,
793	    args: &PushArgs,
794	    layout: &StateLayout,
795	) -> Result<(), Box<dyn std::error::Error>> {
796	    match stage {
797	        Stage::Preflight => stage_preflight(root, state, args),
798	        Stage::Review => stage_review(root, args),
799	        Stage::Message => stage_message(root, state, args, layout),
800	        Stage::CommitApp => stage_commit_app(root, state, args),
801	        Stage::CommitClaude => stage_commit_claude(root, state, args),
802	        Stage::BookmarkBoth => stage_bookmark_both(root, state, args),
803	        Stage::PushApp => stage_push_app(root, state, args),
804	        Stage::FinalizeClaude => stage_finalize_claude(root, state, args),
805	    }
806	}
807	
808	/// Preflight: `vc-x1 sync --check && cargo fmt && cargo clippy
809	/// -D warnings && cargo test`.
810	///
811	/// Sync runs in `--check` mode so divergence with the remote is
812	/// surfaced before we burn cargo cycles, but **not** auto-resolved —
813	/// a rebase mid-push is exactly the kind of unsupervised mutation
814	/// the two approval gates exist to prevent. If sync reports action
815	/// needed, preflight errors and the user resolves explicitly with
816	/// `vc-x1 sync --no-check` before re-running push. The cargo steps
817	/// match CLAUDE.md's pre-commit checklist (minus `cargo install` /
818	/// retest, which are project-specific). All subprocesses run in the
819	/// workspace root so cargo picks up the right `Cargo.toml`. Skipped
820	/// in `--dry-run` since `cargo fmt` writes files.
821	fn stage_preflight(
822	    root: &Path,
823	    state: &PushState,
824	    args: &PushArgs,
825	) -> Result<(), Box<dyn std::error::Error>> {
826	    if args.dry_run {
827	        info!(
828	            "push preflight: [dry-run] would run verify-tracking / vc-x1 sync --check / cargo fmt / clippy / test"
829	        );
830	        return Ok(());
831	    }
832	    info!("push preflight: verify bookmark tracking");
833	    crate::common::verify_tracking(root, &state.bookmark)?;
834	    crate::common::verify_tracking(&claude_path(root), &state.bookmark)?;
835	    info!("push preflight: vc-x1 sync --check");
836	    run("vc-x1", &["sync", "--check"], root)?;
837	    info!("push preflight: cargo fmt");
838	    run("cargo", &["fmt"], root)?;
839	    info!("push preflight: cargo clippy --all-targets -- -D warnings");
840	    run(
841	        "cargo",
842	        &["clippy", "--all-targets", "--", "-D", "warnings"],
843	        root,
844	    )?;
845	    info!("push preflight: cargo test");
846	    run("cargo", &["test"], root)?;
847	    Ok(())
848	}
849	
850	/// Review: first approval gate — "is the work done right?".
851	///
852	/// Shows a `jj diff --stat` of the pending changes in both repos
853	/// and prompts the user to continue. `--yes` short-circuits the
854	/// prompt (required for scripted / non-tty use). In `--dry-run`
855	/// the diff is still shown (that's the point of dry-run — see
856	/// what *would* be reviewed) but approval is auto-granted.
857	fn stage_review(root: &Path, args: &PushArgs) -> Result<(), Box<dyn std::error::Error>> {
858	    let claude = claude_path(root);
859	    let app_arg = root.to_string_lossy();
860	    let claude_arg = claude.to_string_lossy();
861	    info!("push review: pending changes:");
862	    info!("  app ({app_arg}):");
863	    let app_stat = run("jj", &["diff", "--stat", "-R", &app_arg], root)?;
864	    for line in app_stat.lines() {
865	        info!("    {line}");
866	    }
867	    info!("  .claude ({claude_arg}):");
868	    let claude_stat = run("jj", &["diff", "--stat", "-R", &claude_arg], root)?;
869	    for line in claude_stat.lines() {
870	        info!("    {line}");
871	    }
872	    if args.yes {
873	        info!("push review: auto-approved (--yes)");
874	        return Ok(());
875	    }
876	    if args.dry_run {
877	        info!("push review: [dry-run] auto-approved");
878	        return Ok(());
879	    }
880	    if !is_stdin_tty() {
881	        return Err("push review: stdin is not a tty; \
882	                    pass --yes to auto-approve in non-interactive contexts"
883	            .into());

