        return Ok(());
    }
    if args.dry_run {
        info!("push review: [dry-run] auto-approved");
        return Ok(());
    }
    if !is_stdin_tty() {
        return Err("push review: stdin is not a tty; \
                    pass --yes to auto-approve in non-interactive contexts"
            .into());

