    let body_with_trailer = format!("{body}\n\nochid: /.claude/{claude_chid}");
    let app_arg = root.to_string_lossy();
    if args.dry_run {
        info!(
            "push commit-app: [dry-run] would run jj commit -R {app_arg} -m \"{title}\" -m <body+ochid>"
        );
        return Ok(());
    }
    info!("push commit-app: jj commit -R {app_arg}");
    run(
        "jj",
        &[
            "commit",
            "-R",
            &app_arg,
            "-m",
            &title,
            "-m",
            &body_with_trailer,
        ],
        root,
    )?;
    Ok(())
}

/// Pull the title/body pair from CLI args or persisted state,
/// preferring CLI args (override-on-resume case). Returns `Err`
/// when neither source has them — which only happens if
/// `stage_message` didn't run or was force-bypassed.
fn resolve_message(
    state: &PushState,
    args: &PushArgs,
) -> Result<(String, String), Box<dyn std::error::Error>> {
    let title = args
        .title
        .clone()
        .or_else(|| state.title.clone())
        .ok_or("push: title missing — message stage didn't run")?;
    let body = args
        .body
        .clone()
        .or_else(|| state.body.clone())
        .ok_or("push: body missing — message stage didn't run")?;
    Ok((title, body))
}

/// Commit `.claude` with the same title/body and the ochid trailer
/// pointing at the app commit's chid, or skip if `.claude` had no
/// pending changes.
fn stage_commit_claude(
    root: &Path,
    state: &PushState,
    args: &PushArgs,
) -> Result<(), Box<dyn std::error::Error>> {
    if !state.claude_had_changes.unwrap_or(false) {
        info!("push commit-claude: skip (.claude had no pending changes)");
        return Ok(());
    }
    let (title, body) = resolve_message(state, args)?;
    let app_chid = state
        .app_chid
        .as_deref()
        .ok_or("push commit-claude: app_chid not set (message stage didn't run)")?;
    let body_with_trailer = format!("{body}\n\nochid: /{app_chid}");
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if args.dry_run {
        info!(
            "push commit-claude: [dry-run] would run jj commit -R {claude_arg} -m \"{title}\" -m <body+ochid>"
        );
        return Ok(());
    }
    info!("push commit-claude: jj commit -R {claude_arg}");
    run(
        "jj",
        &[
            "commit",
            "-R",
            &claude_arg,
            "-m",
            &title,
            "-m",
            &body_with_trailer,
        ],
        root,
    )?;
    Ok(())
}

/// Advance the bookmark to `@-` in both repos.
fn stage_bookmark_both(
    root: &Path,
    state: &PushState,
    args: &PushArgs,
) -> Result<(), Box<dyn std::error::Error>> {
    let bk = &state.bookmark;
    let app_arg = root.to_string_lossy();
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if args.dry_run {
        info!(
            "push bookmark-both: [dry-run] would run jj bookmark set {bk} -r @- -R {app_arg} / {claude_arg}"
        );
        return Ok(());
    }
    info!("push bookmark-both: jj bookmark set {bk} -r @- -R {app_arg} / {claude_arg}");
    run(
        "jj",
        &["bookmark", "set", bk, "-r", "@-", "-R", &app_arg],
        root,
    )?;
    run(
        "jj",
        &["bookmark", "set", bk, "-r", "@-", "-R", &claude_arg],
        root,
    )?;
    Ok(())
}

/// Push the app repo's bookmark to origin.
fn stage_push_app(
    root: &Path,
    state: &PushState,
    args: &PushArgs,
) -> Result<(), Box<dyn std::error::Error>> {
    let bk = &state.bookmark;
    let app_arg = root.to_string_lossy();
    if args.dry_run {
        info!("push push-app: [dry-run] would run jj git push --bookmark {bk} -R {app_arg}");
        return Ok(());
    }
    info!("push push-app: jj git push --bookmark {bk} -R {app_arg}");
    run(
        "jj",
        &["git", "push", "--bookmark", bk, "-R", &app_arg],
        root,
    )?;
    Ok(())
}

/// Finalize `.claude` via an out-of-process `vc-x1 finalize` call.
/// Shells out rather than calling `finalize::finalize` in-process
/// so `--detach` can fork a child that outlives push's own
/// lifetime. `--no-finalize` turns this stage into a no-op (which
/// is how integration tests avoid spawning a detached process).
fn stage_finalize_claude(
    root: &Path,
    state: &PushState,
    args: &PushArgs,
) -> Result<(), Box<dyn std::error::Error>> {
    if args.no_finalize {
        info!("push finalize-claude: skip (--no-finalize)");
        return Ok(());
    }
    let bk = &state.bookmark;
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if args.dry_run {
        info!(
            "push finalize-claude: [dry-run] would run vc-x1 finalize --repo {claude_arg} --squash --push {bk} --delay 10 --detach"
        );
        return Ok(());
    }
    info!(
        "push finalize-claude: vc-x1 finalize --repo {claude_arg} --squash --push {bk} --delay 10 --detach"
    );
    run(
        "vc-x1",
        &[
            "finalize",
            "--repo",
            &claude_arg,
            "--squash",
            "--push",
            bk,
            "--delay",
            "10",
            "--detach",
            "--log",
            "/tmp/vc-x1-finalize.log",
        ],
        root,
    )?;
    Ok(())
}

/// Verify the saved state still matches reality before any stage runs.
///
/// Catches the failure mode where out-of-band activity (manual finalize,
/// squash + force-push, abandon, etc.) moved the world forward between
/// the prior push and this resume, leaving `state` pointing at a
/// now-bogus halt point. The 0.37.1 dogfood incident is the canonical
/// example: push parked at `finalize-claude` after a failure; manual
/// recovery moved the world forward; the next push resumed at the
/// parked stage, no-op'd, and falsely declared "completed all stages"
/// while working copies still held uncommitted changes.
///
/// Three checks (per chores-06 [61] design):
///
/// 1. `state.app_chid` still resolves in the app repo (not abandoned).
/// 2. After `bookmark-both` has run (state.stage ∈ {PushApp,
///    FinalizeClaude}), the bookmark points at a commit whose chid
///    matches `state.app_chid`.
/// 3. `state.claude_chid` still resolves in `.claude`.
///
/// On any mismatch: error with the exact `vc-x1 push <bookmark>
/// --restart` remediation. A fresh state (no chids yet) is a no-op —
/// nothing to verify.
fn verify_state_sanity(root: &Path, state: &PushState) -> Result<(), Box<dyn std::error::Error>> {
    let Some(app_chid) = &state.app_chid else {
        return Ok(()); // OK: fresh state, nothing to verify yet
    };
    let bookmark = &state.bookmark;
    let root_str = root.to_string_lossy();
    let cwd = Path::new(".");

    // 1. app_chid still resolves.
    run(
        "jj",
        &[
            "log",
            "-r",
            app_chid,
            "--no-graph",
            "-T",
            "\"x\"",
            "-R",
            &root_str,
        ],
        cwd,
    )
    .map_err(|_| -> Box<dyn std::error::Error> {
        format!(
            "state-sanity: app_chid '{app_chid}' has been abandoned or no longer resolves \
             in the app repo. State is stale — run `vc-x1 push {bookmark} --restart` to clear."
        )
        .into()
    })?;

    // 2. bookmark at app_chid (after bookmark-both has run).
    if matches!(state.stage, Stage::PushApp | Stage::FinalizeClaude) {
        let bookmark_chid = run(
            "jj",
            &[
                "log",
                "-r",
                bookmark,
                "--no-graph",
                "-T",
                "change_id.short(12)",
                "-R",
                &root_str,
            ],
            cwd,
        )?;
        let bookmark_chid = bookmark_chid.trim();
        if bookmark_chid != app_chid.as_str() {

            return Err(format!(
                "state-sanity: bookmark '{bookmark}' is at chid '{bookmark_chid}' but \
                 state.app_chid is '{app_chid}'. State is stale — run \
                 `vc-x1 push {bookmark} --restart` to clear."
            )
            .into());
        }
    }

    // 3. claude_chid still resolves.
    if let Some(claude_chid) = &state.claude_chid {
        let claude = claude_path(root);
        let claude_str = claude.to_string_lossy();
        run(
            "jj",
            &[
                "log",
                "-r",
                claude_chid,
                "--no-graph",
                "-T",
                "\"x\"",
                "-R",
                &claude_str,
            ],
            cwd,
        )
        .map_err(|_| -> Box<dyn std::error::Error> {
            format!(
                "state-sanity: claude_chid '{claude_chid}' has been abandoned or no longer \
                 resolves in .claude. State is stale — run \
                 `vc-x1 push {bookmark} --restart` to clear."
            )
            .into()
        })?;
    }

    Ok(())
}

/// Verify the world matches the saved state after all stages have run.
///
/// Counterpart to `verify_state_sanity` (which runs pre-stage). This
/// runs after the stage loop completes and confirms the post-conditions
/// are real — directly addresses the 0.37.1 false-success symptom
/// (push declared "completed all stages" while WC still held
/// uncommitted changes from a stale-state resume).
///
/// Three checks:
///
/// 1. App's bookmark is at a commit whose chid matches `state.app_chid`.
/// 2. App's working copy has no uncommitted changes (commit-app should
///    have captured anything that was there).
/// 3. `.claude`'s bookmark is at `state.claude_chid`'s commit (when set).
///    `.claude`'s WC may legitimately have new session writes from the
///    push run itself — finalize-claude (detached) handles those — so
///    no WC-clean check on `.claude`.
///
/// On any mismatch: returns `Err`. The caller surfaces as a loud
/// warning rather than blocking — push has already crossed the remote
/// boundary, work is live on origin, the warning prompts the user to
/// investigate.
fn verify_completion_sanity(
    root: &Path,
    state: &PushState,
) -> Result<(), Box<dyn std::error::Error>> {
    let bookmark = &state.bookmark;
    let root_str = root.to_string_lossy();
    let cwd = Path::new(".");

    // 1. app bookmark at state.app_chid.
    if let Some(app_chid) = &state.app_chid {
        let actual = run(
            "jj",
