116	/// CLI entry point for the `sync` subcommand.
117	///
118	/// Thin wrapper over `sync_repos` that resolves the `-R` flag into a
119	/// concrete repo list (falling back to the dual-repo default) and
120	/// forwards the rest of the args. Tests call `sync_repos` directly
121	/// with absolute fixture paths.
122	///
123	/// When `--quiet` is set, the global log filter is temporarily clamped
124	/// to `Warn` for the duration of the call and restored on return, so
125	/// `info!` calls throughout sync (plus any subprocess-stderr routed
126	/// through `common::run`) go dark. Errors still surface at `Warn` /
127	/// `Error` so script callers don't lose diagnostics.
128	pub fn sync(args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
129	    let repos = resolve_args_to_repos(args)?;
130	    if args.quiet {
131	        let prev = log::max_level();
132	        log::set_max_level(LevelFilter::Warn);
133	        let result = sync_repos(&repos, args);
134	        log::set_max_level(prev);
135	        result
136	    } else {
137	        sync_repos(&repos, args)
138	    }
139	}
140	
141	/// Sync the given repos against their remotes.
142	///
143	/// Orchestrates the full flow: pre-flight clean-check on every repo,
144	/// snapshot each repo's current op id, then hand off to `run_plan` for
145	/// fetch + classify + (optional) act. On any error, revert every repo
146	/// to its snapshot op via `jj op restore` so the caller sees an atomic
147	/// "either it all went through or nothing changed" outcome.
148	///
149	/// Paths may be relative (resolved against the process cwd) or
150	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
151	/// under parallel `cargo test`.
152	pub fn sync_repos(repos: &[PathBuf], args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
153	    debug!(
154	        "sync: enter (no_check={}, bookmark={}, remote={})",
155	        args.no_check, args.bookmark, args.remote
156	    );
157	
158	    // Preflight: verify bookmark tracking on every repo before any
159	    // fetch/rebase. Implements "Non-tracking-remote bookmark detection"
160	    // — design at:
161	    //   https://github.com/winksaville/vc-x1/blob/main/notes/chores-06.md#non-tracking-remote-bookmark-detection-design
162	    for repo in repos {
163	        crate::common::verify_tracking(repo, &args.bookmark)?;
164	    }
165	
166	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
167	    for repo in repos {
168	        let op_id = current_op_id(repo)?;
169	        debug!("{}: op snapshot = {op_id}", repo.display());
170	        snapshots.push((repo.clone(), op_id));
171	    }
172	
173	    let result = run_plan(&snapshots, args);
174	
175	    if let Err(e) = &result {
176	        warn!("sync failed: {e}");
177	        warn!("reverting all repos to starting state...");
178	        for (repo, op_id) in &snapshots {
179	            match op_restore(repo, op_id) {
180	                Ok(()) => info!("  {}: reverted to op {op_id}", repo.display()),
181	                Err(re) => warn!("  {}: revert failed: {re}", repo.display()),
182	            }
183	        }
184	    }
185	
186	    debug!("sync: exit");
187	    result
188	}
189	
190	/// Fetch and classify each repo, then act (or not, in dry-run).
191	///
192	/// Returns `Err` on the first failure so the caller can trigger the
193	/// cross-repo revert; partial success across repos is *not* a valid
194	/// end state for this command.
195	fn run_plan(
196	    snapshots: &[(PathBuf, String)],
197	    args: &SyncArgs,
198	) -> Result<(), Box<dyn std::error::Error>> {
199	    // Phase 1 — fetch + classify silently.
200	    //
201	    // Each repo's fetch stderr is captured (rather than streamed to
202	    // `info!` via `common::run`) so we can decide after classification
203	    // whether to surface it. `jj git fetch`'s routine "Nothing
204	    // changed." chatter is the main thing we're suppressing here —
205	    // if nothing needs action, the user shouldn't see it.
206	    let mut fetched: Vec<(PathBuf, String)> = Vec::new();
207	    let mut ctxs: Vec<RepoCtx> = Vec::new();
208	    for (repo, op_id) in snapshots {
209	        let stderr = fetch_silent(repo, &args.remote)?;
210	        fetched.push((repo.clone(), stderr));
211	        let state = classify(repo, &args.bookmark, &args.remote)?;
212	        ctxs.push(RepoCtx {
213	            path: repo.clone(),
214	            op_id: op_id.clone(),
215	            state,
216	        });
217	    }
218	
219	    let any_action_needed = ctxs
220	        .iter()
221	        .any(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }));
222	
223	    // Phase 2 — emit status. `--quiet` is enforced globally via the
224	    // log-level clamp in `sync()`, so these `info!` calls are already
225	    // suppressed in scripts; we just shape the output here.
226	    if !any_action_needed {
227	        let n = ctxs.len();
228	        let noun = if n == 1 { "repo" } else { "repos" };
229	        info!("sync: {n} {noun}, all bookmarks up-to-date");
230	    } else {
231	        for (repo, stderr) in &fetched {
232	            info!("{}: fetch {}", repo.display(), args.remote);
233	            for line in stderr.lines() {
234	                info!("{line}");
235	            }
236	        }
237	        for ctx in &ctxs {
238	            log_state(&ctx.path, &ctx.state);
239	        }
240	    }
241	
242	    // Phase 3 — act (subprocess output streams through as usual).
243	    // `act_on_state` and `ensure_at_on_main` short-circuit when
244	    // `args.no_check` is false, so check mode is a true no-op here.
245	    for ctx in &ctxs {
246	        act_on_state(ctx, args)?;
247	        ensure_at_on_main(&ctx.path, &args.bookmark, args.no_check)?;
248	    }
249	
250	    // Phase 4 — check mode is fatal when action would be needed.
251	    // Apply mode (`--no-check`) ran the action above and is done.
